function report = runDegradedSyntheticVisualization(testNumber, options)
%RUNDEGRADEDSYNTHETICVISUALIZATION Inspect one degraded synthetic scene.
%
% Tests 1--3 are tuning fixtures; 4--6 are held-out fixtures. This wrapper
% renders the committed fixture and delegates all matching, metrics, and
% figures to runSyntheticHeightVisualization so the degraded and local
% raster-texture diagnostics execute the same algorithm path.
%
%   1  tuning horizontal plane + noise
%   2  tuning along-track slope + blur
%   3  tuning height step + noise
%   4  held-out cross-track slope + noise
%   5  held-out height step + blur
%   6  held-out horizontal plane + gamma/repeated texture
%
% Display=false suppresses figures only; all numeric products are returned.
% Traceability: algo/main.tex Algorithm 1; Secs. 10.4--10.5 and 14.6;
% Eqs. (71)--(76), (121)--(133).

arguments
    testNumber (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeMember(testNumber, 1:6)} = 1
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = false
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [24, 26]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.CostCurveFraction (1, 2) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.CostCurveFraction, 0), mustBeLessThanOrEqual( ...
        options.CostCurveFraction, 1)} = [0.5, 0.5]
    options.StoreResearchCostVolumes (1, 1) logical = true
    options.CpuImplementation (1, 1) string ...
        {mustBeMember(options.CpuImplementation, ...
        ["optimized", "reference"])} = "optimized"
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
splitFile = fullfile(root, "config", "synthetic", ...
    "degraded_split_v1.json");
split = jsondecode(fileread(splitFile));
fixtures = [string(split.tuningFixtures(:)); ...
    string(split.heldoutFixtures(:))];
fixture = fullfile(fileparts(splitFile), fixtures(testNumber));
c = jsondecode(fileread(fixture));

timer = tic;
renderer = SyntheticPinholeRenderer.fromJson(fixture);
pair = renderer.renderPair;
r = c.movingRadiometry;
pair.MovingImage = SyntheticRadiometry.apply( ...
    pair.MovingImage, renderer.BitDepth, string(r.kind), ...
    Gain=double(r.gain), Offset=double(r.offset), ...
    Gamma=double(r.gamma), BlurSigmaPixels=double(r.blurSigmaPixels), ...
    NoiseSigma=double(r.noiseSigma), Seed=double(r.seed));
inputSeconds = toc(timer);
[truthHeight, truthCorrespondence, truthValid] = truth(renderer, pair);

scene = struct( ...
    "Number", testNumber, "Identifier", string(c.identifier), ...
    "Suite", string(c.suite), "FixtureFile", string(fixture), ...
    "DatasetName", "degraded_split_v1", ...
    "Radiometry", string(r.kind), "InputKind", "rendered-procedural", ...
    "Renderer", renderer, "Pair", pair, ...
    "TruthHeightMetres", truthHeight, ...
    "TruthCorrespondenceXY", truthCorrespondence, ...
    "TruthValid", truthValid, ...
    "SearchRangeMetres", renderer.SearchRangeMetres, ...
    "TargetMotionPerLabelPixels", ...
    renderer.TargetMotionPerLabelPixels, ...
    "Configuration", split, "InputSeconds", inputSeconds);

report = runSyntheticHeightVisualization(scene, ...
    Display=options.Display, UseParallel=options.UseParallel, ...
    NumWorkers=options.NumWorkers, TileSize=options.TileSize, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    LabelBlockSize=options.LabelBlockSize, ...
    CostCurveFraction=options.CostCurveFraction, ...
    StoreResearchCostVolumes=options.StoreResearchCostVolumes, ...
    CpuImplementation=options.CpuImplementation, ...
    WorkingPrecision=options.WorkingPrecision);
clear cleanup
end

function [z, w, valid] = truth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "step"
    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [w, vg, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    valid = vr & vg & inside & visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    valid = vr & vg & inside;
end
valid = valid & pair.ReferenceValid(:);
z = reshape(z, renderer.ImageSize);
w = reshape(w, [renderer.ImageSize, 2]);
valid = reshape(valid, renderer.ImageSize);
end
